mapper.select:
SELECT p.id, p.user_id, p.post_type, p.category_id, p.title, p.content, p.visibility, p.like_count, p.comment_count, p.created_at, p.updated_at, u.name AS user_name, pc.name AS category_name FROM t_timeline_post p LEFT JOIN t_user u ON p.user_id = u.id LEFT JOIN t_post_category pc ON p.category_id = pc.id WHERE p.deleted = 0 AND p.status = 'PUBLISHED' AND p.user_id = #{userId}
AND p.category_id = #{categoryId}
AND YEAR(p.created_at) = #{year}
AND MONTH(p.created_at) = #{month}
ORDER BY p.created_at DESC
